// Lee el payload que envía el backend (Spring Boot -> n8n).
// Cuando viene de un Webhook, el cuerpo del POST llega bajo .body.
const data = $input.first().json.body || $input.first().json || {};
const est = data.estudiante || {};
const doc = data.doctor || {};
const meds = data.medicamentos || [];

const nReceta = String(data.idReceta || '').padStart(4, '0');
const listaMeds = meds.map(m => `<li>${m.nombre || ''}${m.dosis ? ' — ' + m.dosis : ''}${m.duracion ? ' (' + m.duracion + ')' : ''}</li>`).join('');

// Cuerpo del correo (corto y formal). El detalle completo va en el PDF adjunto.
const html = `
<div style="font-family:Arial,Helvetica,sans-serif;max-width:600px;margin:0 auto;color:#1E293B;">
  <div style="background:#8B1414;color:#F9F5F0;padding:18px 24px;border-radius:8px 8px 0 0;">
    <h2 style="margin:0;font-size:18px;">Centro Médico UNI</h2>
    <p style="margin:4px 0 0;font-size:12px;opacity:.9;">Universidad Nacional de Ingeniería</p>
  </div>
  <div style="border:1px solid #E8DDD8;border-top:none;padding:24px;border-radius:0 0 8px 8px;background:#F9F5F0;">
    <p>Hola <strong>${est.nombre || ''}</strong>,</p>
    <p>El doctor <strong>${doc.nombre || ''}</strong>${doc.especialidad ? ' (' + doc.especialidad + ')' : ''} ha registrado tu <strong>receta médica N° ${nReceta}</strong>.</p>
    <p>Adjuntamos el documento oficial en <strong>PDF</strong> con tu diagnóstico y la lista de medicamentos:</p>
    <ul>${listaMeds || '<li>—</li>'}</ul>
    <p style="margin-top:20px;">Para recoger tus medicamentos, acércate a la <strong>farmacia del Centro Médico</strong> presentando la receta adjunta.</p>
    <hr style="border:none;border-top:1px solid #E8DDD8;margin:24px 0;">
    <p style="font-size:12px;color:#64748B;">Mensaje automático del Sistema de Gestión del Centro Médico UNI. No respondas a este correo.</p>
  </div>
</div>`;

const out = {
  json: {
    to: est.email,
    subject: `Tu receta médica N° ${nReceta} - Centro Médico UNI`,
    html
  }
};

// Adjunto PDF: el backend lo manda en base64 (data.pdfBase64).
if (data.pdfBase64) {
  out.binary = {
    receta: {
      data: data.pdfBase64,
      fileName: data.pdfNombre || `receta-${nReceta}.pdf`,
      mimeType: 'application/pdf'
    }
  };
}

return [out];
